  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"./src/generated/prisma\"\n}\n\nenum FoodSource {\n  SYSTEM\n  USER_CREATED\n  AI_GENERATED\n  ADMIN_VERIFIED\n  EXTERNAL_IMPORT\n}\n\nmodel User {\n  id             String          @id @default(uuid())\n  email          String          @unique\n  passwordHash   String\n  createdAt      DateTime        @default(now())\n  updatedAt      DateTime        @updatedAt\n  profile        UserProfile?\n  meals          Meal[]\n  waterLogs      WaterLog[]\n  supplementLogs SupplementLog[]\n  exerciseLogs   ExerciseLog[]\n  mealScans      MealScan[]\n  conversations  Conversation[]\n  travelSessions TravelSession[]\n}\n\nmodel UserProfile {\n  id            String   @id @default(uuid())\n  userId        String   @unique\n  user          User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  fullName      String\n  age           Int\n  gender        String\n  weight        Float // in kg\n  height        Float // in cm\n  activityLevel String // sedentary, lightly_active, moderately_active, very_active\n  goal          String // fat_loss, muscle_gain, maintenance\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n}\n\nmodel Food {\n  id            String     @id @default(uuid())\n  name          String     @unique\n  calories      Float\n  protein       Float\n  carbohydrates Float\n  fats          Float\n  fiber         Float\n  sugar         Float\n  defaultUnit   String     @default(\"g\")\n  servingSize   Float      @default(100)\n  source        FoodSource @default(SYSTEM)\n  createdAt     DateTime   @default(now())\n  updatedAt     DateTime   @updatedAt\n  mealItems     MealItem[]\n}\n\nmodel Meal {\n  id        String     @id @default(uuid())\n  userId    String\n  user      User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  mealType  String // Breakfast, Lunch, Dinner, Snack\n  source    String // manual, scanner, ai_coach\n  createdAt DateTime   @default(now())\n  items     MealItem[]\n  mealScan  MealScan?\n}\n\nmodel MealItem {\n  id            String  @id @default(uuid())\n  mealId        String\n  meal          Meal    @relation(fields: [mealId], references: [id], onDelete: Cascade)\n  foodId        String?\n  food          Food?   @relation(fields: [foodId], references: [id], onDelete: SetNull)\n  foodName      String\n  quantity      Float\n  unit          String // g, piece, cup, serving, etc.\n  calories      Float\n  protein       Float\n  carbohydrates Float\n  fats          Float\n  fiber         Float\n  sugar         Float\n}\n\nmodel WaterLog {\n  id        String   @id @default(uuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  amount    Float // e.g. 250\n  unit      String // ml, oz\n  createdAt DateTime @default(now())\n}\n\nmodel SupplementLog {\n  id        String   @id @default(uuid())\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  name      String // Creatine, Vitamins, etc.\n  dosage    Float // e.g. 5\n  unit      String // g, tablet, capsule, scoop\n  createdAt DateTime @default(now())\n}\n\nmodel ExerciseLog {\n  id              String   @id @default(uuid())\n  userId          String\n  user            User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  activityName    String // Running, Weightlifting, etc.\n  durationMinutes Float\n  caloriesBurned  Float\n  createdAt       DateTime @default(now())\n}\n\nmodel MealScan {\n  id               String   @id @default(uuid())\n  userId           String\n  user             User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  mealId           String?  @unique\n  meal             Meal?    @relation(fields: [mealId], references: [id], onDelete: SetNull)\n  imageUrl         String\n  model            String\n  confidence       Float\n  rawResponse      String\n  processedMatches String // Serialized JSON of matches\n  status           String // DRAFT, CONFIRMED, FAILED\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n}\n\nmodel Conversation {\n  id        String                @id @default(uuid())\n  userId    String\n  user      User                  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title     String\n  createdAt DateTime              @default(now())\n  updatedAt DateTime              @updatedAt\n  messages  ConversationMessage[]\n\n  @@index([userId])\n}\n\nmodel ConversationMessage {\n  id             String                @id @default(uuid())\n  conversationId String\n  conversation   Conversation          @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n  role           String // user, assistant, system\n  content        String // plain text only\n  metadata       String? // JSON string of structured AI payloads\n  tokens         Int                   @default(0)\n  createdAt      DateTime              @default(now())\n  feedback       ConversationFeedback?\n\n  @@index([conversationId])\n}\n\nmodel ConversationFeedback {\n  id        String              @id @default(uuid())\n  messageId String              @unique\n  message   ConversationMessage @relation(fields: [messageId], references: [id], onDelete: Cascade)\n  rating    Int // 1 for thumbs up, -1 for thumbs down\n  comment   String?\n  createdAt DateTime            @default(now())\n}\n\nmodel TravelSession {\n  id        String    @id @default(uuid())\n  userId    String\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  active    Boolean   @default(true)\n  startDate DateTime  @default(now())\n  endDate   DateTime?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@index([userId])\n}\n\nmodel CacheEntry {\n  key       String   @id\n  value     String // cached response string\n  createdAt DateTime @default(now())\n  expiresAt DateTime\n}\n",
